  --glass-border: rgba(255, 255, 255, 0.06);
  --glass-blur: blur(24px);
  
  --primary: #10b981; /* Cyber Emerald */
  --secondary: #3b82f6; /* Royal Blue */
  --accent: #f59e0b; /* Amber Accent */
  
  --text-main: #ffffff;
  --text-dim: #94a3b8;
  --text-muted: #64748b;
  
  --radius-lg: 24px;
  --radius-md: 16px;
  --radius-sm: 10px;
  
  --shadow-premium: 0 10px 40px -10px rgba(0, 0, 0, 0.7);
  --shadow-glow: 0 0 20px rgba(16, 185, 129, 0.15);
}

* {
box-sizing: border-box;
}

::-webkit-scrollbar {
width: 6px; height: 6px;
}

::-webkit-scrollbar-track {
background: rgba(255, 255, 255, 0.02); border-radius: 4px;
}

::-webkit-scrollbar-thumb {
background: rgba(255, 255, 255, 0.1); border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
background: rgba(255, 255, 255, 0.2);
}

body {
margin: 0;
  font-family: 'Outfit', 'Inter', sans-serif;
  background: var(--bg-color);
  background-image: var(--bg-gradient);
  color: var(--text-main);
  overflow: hidden; 
  -webkit-font-smoothing: antialiased;
}

.search-container {
height: 100vh;
  display: flex;
  flex-direction: column;
}

.header {
height: 80px;
  z-index: 100;
  padding: 0 2rem;
  background: rgba(11, 14, 20, 0.6);
  backdrop-filter: var(--glass-blur);
  border-bottom: 1px solid var(--glass-border);
  display: flex;
  align-items: center;
}

.header-content {
width: 100%;
  max-width: 1600px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  gap: 3rem;
}

.logo-area {
display: flex; align-items: center; gap: 1rem; flex-shrink: 0;
}

.logo-icon {
width: 40px; height: 40px;
  background: linear-gradient(135deg, var(--primary), var(--secondary));
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  box-shadow: 0 0 20px rgba(16, 185, 129, 0.3);
}

.logo-text {
font-size: 1.6rem; font-weight: 700; letter-spacing: -1px;
  background: linear-gradient(to right, #fff, var(--primary));
  -webkit-background-clip: text; 
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.search-bar-wrapper {
position: relative; flex: 1; max-width: 650px;
}

.search-input {
width: 100%; background: rgba(255, 255, 255, 0.04);
  border: 1px solid var(--glass-border); border-radius: var(--radius-md);
  padding: 0.85rem 1.25rem 0.85rem 3rem;
  color: #fff; font-size: 1rem; font-family: 'Outfit', sans-serif;
  transition: all 0.3s ease;
}

.search-input:focus {
background: rgba(255, 255, 255, 0.08); border-color: var(--primary);
  box-shadow: var(--shadow-glow); outline: none;
}

.search-icon-inline {
position: absolute; left: 1rem; top: 50%; transform: translateY(-50%);
  color: var(--primary); opacity: 0.8;
}

.main-grid {
display: grid; grid-template-columns: 480px 1fr; flex: 1;
  max-width: 1800px; margin: 0 auto; width: 100%; gap: 1.5rem;
  padding: 1.5rem 2rem; height: calc(100vh - 80px);
}

.results-column {
display: flex; flex-direction: column; height: 100%;
  background: transparent; overflow: hidden; border-radius: var(--radius-lg);
}

.results-header {
display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 1rem; padding: 0 0.5rem; flex-shrink: 0;
}

.scroll-area {
flex: 1; overflow-y: auto; overflow-x: hidden;
  padding-right: 0.5rem; padding-bottom: 2rem;
  display: flex; flex-direction: column; gap: 0.8rem;
}

.paper-card {
flex-shrink: 0; background: var(--glass-panel);
  border: 1px solid var(--glass-border); border-radius: var(--radius-md);
  padding: 1.25rem; cursor: pointer;
  transition: all 0.25s cubic-bezier(0.165, 0.84, 0.44, 1);
  position: relative; overflow: hidden;
}

.paper-card:hover {
transform: scale(1.02); background: rgba(255, 255, 255, 0.06);
  border-color: rgba(16, 185, 129, 0.4); box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4);
}

.paper-card.active {
background: rgba(16, 185, 129, 0.08); border-color: var(--primary);
  box-shadow: var(--shadow-glow);
}

.paper-title {
font-size: 1.05rem; font-weight: 600; line-height: 1.4; margin: 0 0 0.75rem 0;
  color: #ffffff; font-family: 'Inter', sans-serif;
  display: -webkit-box; -webkit-line-clamp: 2; line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;
}

.paper-card.active .paper-title {
-webkit-line-clamp: unset; line-clamp: unset;
}

.badge-row {
display: flex; flex-wrap: wrap; gap: 0.5rem; margin-bottom: 0.5rem;
}

.badge {
display: flex; align-items: center; gap: 0.35rem;
  background: rgba(255, 255, 255, 0.05); padding: 0.3rem 0.6rem;
  border-radius: 6px; font-size: 0.75rem; font-weight: 500; color: var(--text-dim);
}

.paper-abstract {
font-family: 'Inter', sans-serif; font-size: 0.85rem; line-height: 1.6;
  color: var(--text-dim); margin-top: 1rem; padding-top: 1rem;
  border-top: 1px solid var(--glass-border);
}

.graph-column {
background: var(--glass-panel); backdrop-filter: var(--glass-blur);
  border-radius: var(--radius-lg); border: 1px solid var(--glass-border);
  position: relative; overflow: hidden; display: flex; flex-direction: column;
}

.graph-top-bar {
display: flex; justify-content: space-between; align-items: center;
  padding: 1rem 1.5rem; border-bottom: 1px solid var(--glass-border);
  background: rgba(11, 14, 20, 0.4); z-index: 10;
}

.graph-title {
font-size: 1.25rem; font-weight: 600; margin: 0; color: #fff;
}

.graph-controls {
display: flex; gap: 1.2rem; align-items: center;
  font-size: 0.85rem; color: var(--text-dim);
}

.control-item {
display: flex; align-items: center; gap: 0.5rem; cursor: pointer;
}

.control-item input[type="checkbox"] {
accent-color: var(--primary); cursor: pointer; width: 14px; height: 14px;
}

.control-item input[type="range"] {
width: 80px; accent-color: var(--primary);
}

.focus-btn {
background: rgba(16, 185, 129, 0.15); color: var(--primary);
  border: 1px solid rgba(16, 185, 129, 0.3); border-radius: 6px;
  padding: 0.4rem 0.8rem; font-size: 0.8rem; cursor: pointer;
  transition: all 0.2s; display: flex; align-items: center; gap: 0.4rem; font-family: 'Outfit', sans-serif;
}

.focus-btn:hover {
background: rgba(16, 185, 129, 0.25);
}

.graph-container {
flex: 1; position: relative; cursor: grab; background: var(--bg-color);
}

.graph-container:active {
cursor: grabbing;
}

.graph-tooltip {
position: absolute; background: rgba(11, 14, 20, 0.95);
  border: 1px solid var(--glass-border); padding: 0.6rem 1rem; border-radius: 8px;
  pointer-events: none; color: #fff; font-size: 0.85rem;
  box-shadow: 0 4px 15px rgba(0,0,0,0.5); transform: translate(-50%, -100%);
  margin-top: -15px; z-index: 100; white-space: nowrap; backdrop-filter: blur(8px);
}

.skeleton {
background: linear-gradient(90deg, rgba(255,255,255,0.03) 25%, rgba(255,255,255,0.08) 50%, rgba(255,255,255,0.03) 75%);
  background-size: 200% 100%; animation: shimmer 1.5s infinite; border-radius: 4px;
}

@keyframes shimmer {
0% { background-position: 200% 0; } 100% { background-position: -200% 0; }
}

.legend-chip {
background: rgba(255, 255, 255, 0.05); padding: 0.4rem 0.8rem;
  border-radius: 100px; font-size: 0.75rem; color: #fff;
  display: flex; align-items: center; gap: 0.5rem; border: 1px solid rgba(255, 255, 255, 0.08);
}

.legend-chip .dot {
width: 8px; height: 8px; border-radius: 50%;
}

.search-submit-btn {
position: absolute; right: 6px; top: 50%; transform: translateY(-50%);
  background: linear-gradient(135deg, var(--primary), var(--secondary));
  color: #0b0e14; border: none; padding: 0.5rem 1rem; border-radius: 8px;
  font-weight: 700; font-size: 0.85rem; font-family: 'Outfit', sans-serif;
  display: flex; align-items: center; gap: 0.4rem; cursor: pointer; transition: all 0.2s;
}

.search-submit-btn:hover {
filter: brightness(1.2);
}
